import "./AddRecipe.css";
import { useState, useEffect } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function AddRecipe() {
  const navigate = useNavigate();
  const token = localStorage.getItem("token");

  const [title, setTitle] = useState("");
  const [ingredients, setIngredients] = useState("");
  const [steps, setSteps] = useState("");
  const [cookingTime, setCookingTime] = useState("");
  const [difficulty, setDifficulty] = useState("Easy");
  const [image, setImage] = useState(null);

  // 🔐 Protect page
  useEffect(() => {
    if (!token) {
      alert("Please login first ❌");
      navigate("/login");
    }
  }, [token, navigate]);

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const formData = new FormData();
      formData.append("title", title);
      formData.append("ingredients", ingredients);
      formData.append("steps", steps);
      formData.append("cooking_time", cookingTime);
      formData.append("difficulty", difficulty);

      if (image) {
        formData.append("image", image);
      }

      const res = await axios.post(
        "http://127.0.0.1:8000/api/recipes/add/",
        formData,
        {
          headers: {
            Authorization: `Token ${token}`,
          },
        }
      );

      console.log("SUCCESS:", res.data);
      alert("Recipe added successfully ✅");

    } catch (error) {
      console.log("ERROR:", error.response?.data); // 👈 IMPORTANT
      alert("Failed to add recipe ❌");
    }
  };

  return (
    <div className="recipe-container">
      <div className="recipe-card">
        <h2>Add Recipe</h2>

        <form onSubmit={handleSubmit}>
          <input type="text" placeholder="Recipe Title"
            value={title} onChange={(e) => setTitle(e.target.value)} required />

          <textarea placeholder="Ingredients"
            value={ingredients} onChange={(e) => setIngredients(e.target.value)} required />

          <textarea placeholder="Steps"
            value={steps} onChange={(e) => setSteps(e.target.value)} required />

          <input type="number" placeholder="Cooking Time"
            value={cookingTime} onChange={(e) => setCookingTime(e.target.value)} required />

          <select value={difficulty} onChange={(e) => setDifficulty(e.target.value)}>
            <option>Easy</option>
            <option>Medium</option>
            <option>Hard</option>
          </select>

          <input type="file" onChange={(e) => setImage(e.target.files[0])} />

          <button type="submit">Add Recipe</button>
        </form>
      </div>
    </div>
  );
}
